  1	// ─── Checkout lifecycle ───────────────────────────────────────────────────────
  2	
  3	export type CheckoutStatus =
  4	  | "active"
  5	  | "checkin_queued"
  6	  | "uploading"
  7	  | "verifying"
  8	  | "complete"
  9	  | "discarded"
 10	  | "error"
 11	  | "conflict";
 12	
 13	export interface CheckoutRecord {
 14	  id: string;                  // UUID from DB
 15	  assetId: string;
 16	  userId: string;
 17	  deviceId: string | null;
 18	  status: CheckoutStatus;
 19	  checkedOutAt: string;        // ISO timestamp
 20	  checkedInAt: string | null;
 21	  // Asset info
 22	  filename: string;
 23	  relativePath: string;
 24	  rootId: string;
 25	  // File state
 26	  sourceHash: string;
 27	  sourceSize: number;
 28	  // Local paths (machine-specific, not in DB)
 29	  workspacePath: string;
 30	  snapshotPath: string | null;
 31	  // Upload progress (in-memory only)
 32	  uploadProgress: number | null; // 0–100
 33	  errorMessage: string | null;
 34	}
 35	
 36	// ─── Root validation ──────────────────────────────────────────────────────────
 37	
 38	export type ValidationResult =
 39	  | { ok: true; resolvedPath: string }
 40	  | { ok: false; reason: "forbidden"; message: string }
 41	  | { ok: false; reason: "no_marker"; message: string }
 42	  | { ok: false; reason: "wrong_root_id"; expected: string; actual: string; message: string }
 43	  | { ok: false; reason: "too_deep"; suggestedPath: string; message: string }
 44	  | { ok: false; reason: "too_shallow"; suggestedPath: string; message: string };
 45	
 46	// ─── Root mappings ────────────────────────────────────────────────────────────
 47	
 48	export interface RootMapping {
 49	  root_id: string;           // e.g. "design_hot"
 50	  display_name: string;      // e.g. "Design Hot"
 51	  local_path: string;        // e.g. "C:\\Users\\Maria\\Seafile\\Design_Hot"
 52	  marker_verified: boolean;
 53	}
 54	
 55	// ─── Config (persisted locally) ───────────────────────────────────────────────
 56	
 57	export interface LocalConfig {
 58	  deviceId: string | null;
 59	  deviceName: string;
 60	  deviceOs: "windows" | "macos";
 61	  helperVersion: string;
 62	  damUrl: string;
 63	  supabaseUrl: string;        // API base URL — auto-discovered from ${damUrl}/dam-config.json
 64	  supabaseAnonKey: string;    // Public anon key — auto-discovered from ${damUrl}/dam-config.json
 65	  workspacePath: string;
 66	  rootMappings: RootMapping[];
 67	}
 68	
 69	// ─── IPC channel types ────────────────────────────────────────────────────────
 70	
 71	export type IpcChannel =
 72	  | "get-checkouts"
 73	  | "get-config"
 74	  | "save-config"
 75	  | "open-file"
 76	  | "reveal-file"
 77	  | "checkin"
 78	  | "discard"
 79	  | "open-dam"
 80	  | "get-auth-state"
 81	  | "logout";
 82	
 83	export interface IpcResponse<T = unknown> {
 84	  ok: boolean;
 85	  data?: T;
 86	  error?: string;
 87	}
 88	
 89	// ─── Auth ─────────────────────────────────────────────────────────────────────
 90	
 91	export interface AuthState {
 92	  loggedIn: boolean;
 93	  userId: string | null;
 94	  email: string | null;
 95	  accessToken: string | null;
 96	}
 97	
 98	// ─── Upload queue ─────────────────────────────────────────────────────────────
 99	
100	export interface UploadJob {
101	  checkoutId: string;
102	  snapshotPath: string;
103	  uploadMethod: "synology_file_station" | "webdav" | "smb_local";
104	  synologyUrl: string | null;
105	  synologyPort: string;
106	  relativePath: string;
107	  filename: string;
108	  tempSuffix: string;
109	  retryCount: number;
110	  addedAt: number; // Date.now()
111	}

